1	Card	27	1	2026-05-16 04:27:51.30927+00	{"description":"Evolución mensual de ingresos totales para identificar tendencias y estacionalidad.","archived":false,"collection_position":null,"table_id":null,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Ingresos totales por mes","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"database":2,"type":"native","native":{"template-tags":{},"query":"SELECT\\r\\n    DATE_TRUNC('month', p.fecha) AS mes,\\r\\n    SUM(p.monto) AS ingresos_totales\\r\\nFROM pago p\\r\\nGROUP BY mes\\r\\nORDER BY mes;"}},"parameter_mappings":[],"display":"line","collection_preview":true,"visualization_settings":{"graph.dimensions":["mes"],"graph.metrics":["ingresos_totales"]},"parameters":[]}	f	t	\N	t	v0.50.20 (df82d58)
