4	Card	28	1	2026-05-16 04:30:02.080809+00	{"description":"Ranking de las 5 tiendas con mayor volumen de ingresos para priorizar inversión y expansión.","archived":false,"collection_position":null,"table_id":null,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Top 5 tiendas por ingresos","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"database":2,"type":"native","native":{"template-tags":{},"query":"SELECT\\r\\n    t.nombre AS tienda,\\r\\n    SUM(p.monto) AS ingresos_totales\\r\\nFROM pago p\\r\\nJOIN pedido pe ON p.id_pedido = pe.id_pedido\\r\\nJOIN tienda t ON pe.id_tienda = t.id_tienda\\r\\nGROUP BY t.nombre\\r\\nORDER BY ingresos_totales DESC\\r\\nLIMIT 5;"}},"parameter_mappings":[],"display":"row","collection_preview":true,"visualization_settings":{"graph.dimensions":["tienda"],"graph.metrics":["ingresos_totales"]},"parameters":[]}	f	t	\N	t	v0.50.20 (df82d58)
