6	Card	29	1	2026-05-16 04:31:21.699887+00	{"description":"Distribución de pedidos e ingresos entre canal físico y digital para decisiones de estrategia comercial.","archived":false,"collection_position":null,"table_id":null,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Ventas por canal: tienda vs online","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"database":2,"type":"native","native":{"template-tags":{},"query":"SELECT\\r\\n    pe.canal,\\r\\n    COUNT(pe.id_pedido) AS total_pedidos,\\r\\n    SUM(p.monto) AS ingresos_totales\\r\\nFROM pedido pe\\r\\nJOIN pago p ON pe.id_pedido = p.id_pedido\\r\\nWHERE pe.estado = 'completado'\\r\\nGROUP BY pe.canal;"}},"parameter_mappings":[],"display":"pie","collection_preview":true,"visualization_settings":{"pie.dimension":"canal","pie.metric":"ingresos_totales"},"parameters":[]}	f	t	\N	t	v0.50.20 (df82d58)
