13	Card	32	1	2026-05-16 04:37:02.164525+00	{"description":"Gasto promedio por pedido según segmento (VIP, regular, nuevo) para personalizar estrategias comerciales.","archived":false,"collection_position":null,"table_id":null,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Ticket promedio por segmento de cliente","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"database":2,"type":"native","native":{"template-tags":{},"query":"SELECT\\r\\n    cl.segmento,\\r\\n    ROUND(AVG(p.monto), 2) AS ticket_promedio,\\r\\n    COUNT(DISTINCT pe.id_pedido) AS total_pedidos\\r\\nFROM pago p\\r\\nJOIN pedido pe ON p.id_pedido = pe.id_pedido\\r\\nJOIN cliente cl ON pe.id_cliente = cl.id_cliente\\r\\nWHERE pe.estado = 'completado'\\r\\nGROUP BY cl.segmento\\r\\nORDER BY ticket_promedio DESC;"}},"parameter_mappings":[],"display":"bar","collection_preview":true,"visualization_settings":{"graph.dimensions":["segmento"],"graph.metrics":["ticket_promedio"]},"parameters":[]}	f	t	\N	t	v0.50.20 (df82d58)
